    let mut entries = tokio::task::spawn_blocking(move || {
        corvia_kernel::knowledge_files::read_scope(&data_dir, &scope_id).unwrap_or_default()
    })
    .await
    .unwrap_or_else(|e| {
        tracing::warn!(error = %e, "activity_feed_load_failed");
        Vec::new()
    });

